package com.restaurantcraft.item;
import com.restaurantcraft.entity.CustomerEntity; import net.minecraft.network.chat.Component; import net.minecraft.sounds.SoundEvents; import net.minecraft.sounds.SoundSource; import net.minecraft.world.*; import net.minecraft.world.entity.LivingEntity; import net.minecraft.world.entity.player.Player; import net.minecraft.world.item.*;
public class MopItem extends Item { public MopItem(Properties p){super(p);} public InteractionResult interactLivingEntity(ItemStack stack, Player player, LivingEntity target, InteractionHand hand){ if(!player.level().isClientSide && target instanceof CustomerEntity c){ if(c.canBeMoppedBy(player)){ c.failAndLeave(true); player.displayClientMessage(Component.translatable("message.restaurant_craft.mop_success"),true); player.level().playSound(null,c.blockPosition(), SoundEvents.VILLAGER_NO, SoundSource.NEUTRAL,1,1); } else player.displayClientMessage(Component.translatable("message.restaurant_craft.not_owner"),true); return InteractionResult.sidedSuccess(player.level().isClientSide);} return InteractionResult.PASS; } }
